197	 * @param drClusters - Array of DRClusterKind objects representing all DR clusters.
198	 * @param mirrorPeers - Array of MirrorPeerKind objects representing mirror peer relationships.
199	 * @returns Array of DRClusterKind objects that are not paired in any mirror peer.
200	 */
201	const getUnpairedDRClusters = (
202	  drClusters: DRClusterKind[],
203	  mirrorPeers: MirrorPeerKind[]
