205	  const pairedClusters = new Set<string>();
206	  mirrorPeers.forEach((mp) => {
207	    const managedS3 = mp?.spec?.manageS3;
208	    mp?.spec?.items?.forEach((item) => {
209	      if (managedS3) pairedClusters.add(item.clusterName);
210	    });
211	  });
212	  return drClusters.filter((dc) => !pairedClusters.has(dc.metadata.name));
213	};
